changeSet.sql:
ALTER TABLE tenants
    ADD COLUMN IF NOT EXISTS plan VARCHAR(50) NOT NULL DEFAULT 'FREE'
        CHECK (plan IN ('FREE', 'STARTER', 'PRO', 'ENTERPRISE'));

ALTER TABLE tenants
    ADD COLUMN IF NOT EXISTS monthly_request_limit INT NOT NULL DEFAULT 10000;

-- Back-fill existing tenants (e.g. your default seed tenant)
UPDATE tenants SET plan = 'FREE', monthly_request_limit = 10000
WHERE plan IS NULL OR monthly_request_limit IS NULL;
